mapper.select:
SELECT DISTINCT p.权限编码 FROM ROLE_PERMISSION rp JOIN PERMISSION p ON rp.权限编号 = p.权限编号 WHERE rp.角色编号 IN
#{roleId}
AND p.权限编码 IS NOT NULL AND p.权限编码 != ''

SELECT COUNT(1)
FROM EMPLOYEE e
WHERE e.员工编码 = #{employeeId}
  AND (
      e.角色 = '超级管理员'
      OR EXISTS (
          SELECT 1
          FROM EMPLOYEE_ROLE er
          JOIN ROLE r ON er.角色编号 = r.角色编号
          WHERE er.员工编码 = #{employeeId}
            AND r.角色名称 IN ('super_admin', '管理员', '系统管理员', 'ADMIN')
      )
  )
